UPDATE places SET lat = 59.25625447359894, lng = 17.2202665897132, description = 'På Gripsholms slott sägs det att dörrhandtag rör sig av sig själva, och vissa har påstått sig möta vålnaden av drottning Kristina av Holstein-Gottorp i de gamla salarna. I slottsteatern kan man höra klockor ringa. Trots att några sådana inte längre finns där. 

