UPDATE places SET lat = 60.875466841721604, lng = 10.71803205300829, description = 'På en gård strax utanför Gjøvik utspelar sig berättelser som skulle kunna komma direkt från en skräckfilm. Denna gård, som varit föremål för många paranormala undersökningar, är känd för sina återkommande oförklarliga händelser och rykten om gästvänliga. Men också rastlösa andar.

